### 1. Three.js (Web-Based 3D)
You can use JavaScript with the Three.js library to create a simple 3D house in a web browser:

```html
<!DOCTYPE html>
<html>
<head>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
</head>
<body>
  <script>
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
    const renderer = new THREE.WebGLRenderer();
    renderer.setSize(window.innerWidth, window.innerHeight);
    document.body.appendChild(renderer.domElement);

    // House materials
    const wallMaterial = new THREE.MeshLambertMaterial({ color: 0x8B4513 });
    const roofMaterial = new THREE.MeshLambertMaterial({ color: 0x800000 });

    // House body
    const house = new THREE.Mesh(new THREE.BoxGeometry(4, 3, 4), wallMaterial);
    scene.add(house);

    // Roof
    const roof = new THREE.Mesh(new THREE.ConeGeometry(3, 2, 4), roofMaterial);
    roof.position.y = 4.5;
    scene.add(roof);

    // Lighting
    const light = new THREE.DirectionalLight(0xffffff, 1);
    light.position.set(5, 10, 7);
    scene.add(light);
    scene.add(new THREE.AmbientLight(0x404040));

    camera.position.z = 10;
    camera.position.y = 5;

    function animate() {
      requestAnimationFrame(animate);
      renderer.render(scene, camera);
    }
    animate();
  </script>
</body>
</html>
```

### 2. Blender (Python Script)
You can use Blender's Python API to generate a basic 3D house:

```python
import bpy

# Clear existing objects
bpy.ops.object.select_all(action='SELECT')
bpy.ops.object.delete()

# Create house body
bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 0, 0))
house = bpy.context.active_object
house.scale = (4, 3, 4)

# Create roof
bpy.ops.mesh.primitive_cone_add(radius1=2, depth=2, location=(0, 4.5, 0))
roof = bpy.context.active_object
roof.rotation_euler = (0, 0, 0)

# Apply materials
for obj in bpy.data.objects:
    mat = bpy.data.materials.new(name="Material")
    obj.data.materials.append(mat)
```

